{
  "title": "हाइब्रिड सर्च",
  "group": "रिट्रीवल",
  "options": [
    {
      "text": "रिडंडेंसी के लिए एक ही क्वेरी को दो बार चलाना"
    },
    {
      "text": "एक ही कॉरपस पर दो अलग-अलग एम्बेडिंग मॉडल का उपयोग करना"
    },
    {
      "text": "बेहतर रिट्रीवल के लिए वेक्टर सर्च और कीवर्ड सर्च को जोड़ना"
    },
    {
      "text": "एक ही समय में कई वेक्टर डेटाबेस में खोज करना"
    }
  ],
  "questionProse": [
    "RAG सिस्टम में, \"हाइब्रिड सर्च\" का तात्पर्य है:"
  ],
  "explanationProse": [
    "हाइब्रिड सर्च **वेक्टर सर्च** (एम्बेडिंग्स के जरिए सेमांटिक सिमिलैरिटी) और **कीवर्ड सर्च** (BM25 / फुल-टेक्स्ट सर्च) को मिलाता है, क्योंकि ये दोनों पूरक तरीकों से फेल होते हैं:\n\n    - वेक्टर सर्च सटीक शब्दों (exact terms) में कमजोर पड़ता है: प्रोडक्ट नाम, एरर कोड, मॉडल नंबर, तकनीकी आइडेंटिफायर\n    - कीवर्ड सर्च पर्यायवाची वाक्यों (paraphrasing) में कमजोर पड़ता है: \"how do I cancel\" vs. \"terminate subscription\"\n\n    दोनों के रिजल्ट्स को **Reciprocal Rank Fusion (RRF)** के जरिए फ्यूज किया जाता है — एक रैंकिंग एल्गोरिदम जो नॉर्मलाइज्ड स्कोर की जरूरत के बिना, कई रैंक की गई लिस्ट्स के पोजीशन को मिलाता है।\n\n    दोनों को Postgres में `pgvector` + `tsvector` के साथ इस्तेमाल किया जा सकता है। शायद आपको अलग से कोई सर्च सर्विस की जरूरत ही न पड़े।"
  ]
}
